#include <iostream>
#include <ranges>
#include <vector>

int main() {
    std::size_t count{};
    if (!(std::cin >> count) || count > 100) return 1;
    std::vector<long long> values(count);
    for (auto& value : values) if (!(std::cin >> value)) return 1;
    auto result = values | std::views::filter([](long long value) { return value % 2 == 0; }) | std::views::transform([](long long value) { return value * value; });
    bool first = true;
    for (long long value : result) { if (!first) std::cout << ' '; first = false; std::cout << value; }
    std::cout << '\n';
}
